#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000.0f

typedef struct {
    char entry[REC_LENGTH];
    float dist;
} neighbor_t;

// Safe float parser with bounds checking
float parse_float_safe(const char *str, int start_idx, int max_len) {
    float result = 0.0f;
    float sign = 1.0f;
    int idx = start_idx;

    if (idx >= max_len) return 0.0f;

    // Skip whitespace
    while (idx < max_len && (str[idx] == ' ' || str[idx] == '\t')) {
        idx++;
    }

    if (idx >= max_len) return 0.0f;

    // Handle sign
    if (str[idx] == '-') {
        sign = -1.0f;
        idx++;
    } else if (str[idx] == '+') {
        idx++;
    }

    if (idx >= max_len) return 0.0f;

    // Parse integer part
    while (idx < max_len && str[idx] >= '0' && str[idx] <= '9') {
        result = result * 10.0f + (str[idx] - '0');
        idx++;
    }

    // Parse fractional part
    if (idx < max_len && str[idx] == '.') {
        idx++;
        float fraction = 0.0f;
        float divisor = 1.0f;
        while (idx < max_len && str[idx] >= '0' && str[idx] <= '9') {
            fraction = fraction * 10.0f + (str[idx] - '0');
            divisor *= 10.0f;
            idx++;
        }
        result += fraction / divisor;
    }

    return sign * result;
}

kernel void compute_distances(
    const char *sandbox,
    float *z,
    float target_lat,
    float target_long,
    int rec_count)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    int base_idx = i * REC_LENGTH;
    int lat_idx = base_idx + LATITUDE_POS - 1;

    // Ensure we don't read out of bounds for this record
    int max_idx = base_idx + REC_LENGTH;

    float tmp_lat = parse_float_safe(sandbox, lat_idx, max_idx);

    // Longitude is 5 chars after latitude start in the original code: rec_iter+5
    // The original code: atof(rec_iter+5) where rec_iter points to lat start
    int long_idx = lat_idx + 5;
    float tmp_long = parse_float_safe(sandbox, long_idx, max_idx);

    float diff_lat = tmp_lat - target_lat;
    float diff_long = tmp_long - target_long;

    z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
}

kernel void update_neighbors(
    const char *sandbox,
    neighbor_t *neighbors,
    const float *z,
    int rec_count,
    int k)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    float current_dist = z[i];

    // Find max distance in neighbors (sequential scan within kernel)
    float max_dist = OPEN; // Initialize to OPEN (large value)
    int max_idx = -1;

    for (int j = 0; j < k; j++) {
        if (neighbors[j].dist > current_dist) {
            if (max_idx == -1 || neighbors[j].dist > max_dist) {
                max_dist = neighbors[j].dist;
                max_idx = j;
            }
        }
    }

    // If we found a neighbor slot that is larger than current_dist, replace it
    if (max_idx != -1) {
        // Copy record string
        int base_idx = i * REC_LENGTH;
        for (int c = 0; c < REC_LENGTH - 1; c++) {
            neighbors[max_idx].entry[c] = sandbox[base_idx + c];
        }
        neighbors[max_idx].entry[REC_LENGTH - 1] = '\0';
        neighbors[max_idx].dist = current_dist;
    }
}
